SELECT COUNT(*) AS total_active_committees
FROM committees
WHERE committee_status = 'active';

SELECT DISTINCT contributors.contributor_name
FROM contributors
JOIN contributions ON contributors.contributor_id = contributions.contributor_id;

SELECT c.committee_name, fp.filing_period_name
FROM committees c
JOIN filing_periods fp ON c.filing_period_id = fp.filing_period_id;

SELECT committee_name, committee_type, chairperson, contact_email, contact_phone
FROM committees
WHERE committee_status = 'active';

SELECT candidate_id
FROM candidates
WHERE candidate_id = 1;
